use dioxus::logger::tracing::{info, warn};
use ghostkey_common::{GhostkeyRequest, GhostkeyResponse};

use crate::api;
use crate::components::ghostkey_list;
use crate::components::toast::{self, ToastKind};

// Generated by build.rs from legacy_delegates.toml
include!(concat!(env!("OUT_DIR"), "/legacy_delegates.rs"));

const MIGRATION_FLAG: &str = "ghostkey_migration_done";

/// Attempt to migrate ghostkeys from legacy delegates to the current one.
pub async fn try_migrate() {
    if LEGACY_DELEGATES.is_empty() {
        return;
    }

    // Check if already migrated (persistent across sessions)
    #[cfg(target_arch = "wasm32")]
    if is_migration_done() {
        return;
    }

    info!(
        "Checking {} legacy delegate(s) for migration",
        LEGACY_DELEGATES.len()
    );

    #[cfg(all(
        target_family = "wasm",
        not(any(feature = "no-sync", feature = "example-data"))
    ))]
    {
        use freenet_stdlib::prelude::{CodeHash, DelegateKey};

        let current_key = api::delegate::get_current_delegate_key();
        let mut migrated_count = 0;

        for (delegate_key_bytes, code_hash_bytes) in LEGACY_DELEGATES {
            let legacy_key = DelegateKey::new(*delegate_key_bytes, CodeHash::new(*code_hash_bytes));

            if legacy_key == current_key {
                continue;
            }

            info!("Trying legacy delegate: {}", legacy_key.encode());

            match api::delegate::send_to_delegate(
                &legacy_key,
                GhostkeyRequest::ExportAllGhostKeys,
                5,
            )
            .await
            {
                Ok(GhostkeyResponse::ExportAllResult { keys }) => {
                    if keys.is_empty() {
                        info!("Legacy delegate has no keys");
                        continue;
                    }

                    info!("Found {} key(s) in legacy delegate", keys.len());

                    for exported in &keys {
                        match api::delegate::send_request(GhostkeyRequest::ImportGhostKey {
                            certificate_pem: exported.certificate_pem.clone(),
                            signing_key_pem: exported.signing_key_pem.clone(),
                            master_verifying_key_pem: None,
                        })
                        .await
                        {
                            Ok(GhostkeyResponse::ImportResult {
                                fingerprint,
                                notary_info,
                            }) => {
                                info!("Migrated ghostkey: {fingerprint}");
                                ghostkey_list::add_ghostkey(ghostkey_common::GhostKeyInfo {
                                    fingerprint,
                                    label: exported.label.clone(),
                                    notary_info,
                                    verifying_key_bytes: None,
                                });
                                migrated_count += 1;
                            }
                            Ok(GhostkeyResponse::Error { message }) => {
                                info!("Skip {}: {message}", exported.fingerprint);
                            }
                            other => {
                                warn!("Failed to re-import {}: {other:?}", exported.fingerprint);
                            }
                        }
                    }

                    // Migrate labels
                    for exported in &keys {
                        if let Some(label) = &exported.label {
                            let _ = api::delegate::send_request(GhostkeyRequest::SetLabel {
                                fingerprint: exported.fingerprint.clone(),
                                label: label.clone(),
                            })
                            .await;
                        }
                    }
                }
                Ok(GhostkeyResponse::Error { message }) => {
                    warn!("Legacy delegate error: {message}");
                }
                Err(e) => {
                    info!("Legacy delegate not reachable: {e}");
                }
                other => {
                    warn!("Unexpected response from legacy delegate: {other:?}");
                }
            }
        }

        if migrated_count > 0 {
            toast::show(
                format!("Migrated {migrated_count} ghostkey(s) from previous version"),
                ToastKind::Success,
            );
        }
    }

    mark_migration_done();
}

/// Check if migration was already done for the current delegate version.
/// Stores the delegate key encoding so it resets when the WASM changes.
#[cfg(target_arch = "wasm32")]
fn is_migration_done() -> bool {
    let current = current_delegate_id();
    web_sys::window()
        .and_then(|w| w.local_storage().ok().flatten())
        .and_then(|s| s.get_item(MIGRATION_FLAG).ok().flatten())
        .map_or(false, |stored| stored == current)
}

fn mark_migration_done() {
    #[cfg(target_arch = "wasm32")]
    {
        if let Some(storage) = web_sys::window().and_then(|w| w.local_storage().ok().flatten()) {
            let _ = storage.set_item(MIGRATION_FLAG, &current_delegate_id());
        }
    }
}

#[cfg(all(
    target_family = "wasm",
    not(any(feature = "no-sync", feature = "example-data"))
))]
fn current_delegate_id() -> String {
    api::delegate::get_current_delegate_key().encode()
}

#[cfg(any(
    not(target_family = "wasm"),
    feature = "no-sync",
    feature = "example-data"
))]
fn current_delegate_id() -> String {
    "mock".to_string()
}
